import { useMap } from '@vis.gl/react-maplibre';
import { useMemo, useRef, type PropsWithChildren } from 'react';

import { MapInitialViewContext } from '../contexts/map-initial-view.context.js';
import type { ViewState } from '../types/map-view.js';

/**
 * This default center is unreachable in runtime, but useful for testing and type-safety
 */
const DEFAULT_CENTER = { lat: 0, lng: 0 };

/**
 *
 * Since the initial view state can be determined in 2 different ways
 * this provider takes care of taking a snapshot of the initial state that was
 * set when the map was initialized and normalize it storing the latitude
 * longitude and zoom to later retrieve it in the Reset Toolbar button.
 *
 * Notice how this Provider is design to not trigger any re-renders and just
 * hold the initial state view.
 */
export const MapInitialViewProvider = ({
  children,
}: PropsWithChildren<ViewState>) => {
  const { current: map } = useMap();
  const boundaries = useRef(map?.getCenter() ?? DEFAULT_CENTER);
  const zoom = useRef(map?.getZoom()).current;

  const { lng: longitude, lat: latitude } = boundaries.current;

  return (
    <MapInitialViewContext.Provider
      value={useMemo(
        () => ({ latitude, longitude, zoom }),
        [latitude, longitude, zoom],
      )}
    >
      {children}
    </MapInitialViewContext.Provider>
  );
};
